import { describe, it, expect } from "vitest"
import { cartReducer } from "./cart"

describe("cartReducer", () => {
  it("adds a new item to the cart", () => {
    const result = cartReducer([], {
      type: "add",
      item: { id: "1", name: "Rose Bouquet", price: 4500 },
    })
    expect(result).toHaveLength(1)
    expect(result[0].quantity).toBe(1)
  })

  it("increments quantity for existing items", () => {
    const state = [{ id: "1", name: "Rose Bouquet", price: 4500, quantity: 1 }]
    const result = cartReducer(state, {
      type: "add",
      item: { id: "1", name: "Rose Bouquet", price: 4500 },
    })
    expect(result[0].quantity).toBe(2)
  })

  it("removes an item from the cart", () => {
    const state = [{ id: "1", name: "Rose Bouquet", price: 4500, quantity: 1 }]
    const result = cartReducer(state, { type: "remove", id: "1" })
    expect(result).toHaveLength(0)
  })
})
